   150  // enforceExistingCgroup updates the limits `rl` on existing cgroup `cName` using `cgroupManager` interface.
   151  func (cm *containerManagerImpl) enforceExistingCgroup(logger klog.Logger, cNameStr string, rl v1.ResourceList, compressibleResources bool) error {
   152          cName := cm.cgroupManager.CgroupName(cNameStr)
   153          rp := cm.getCgroupConfig(rl, compressibleResources)
   154          if rp == nil {
   155                  return fmt.Errorf("%q cgroup is not configured properly", cName)
   156          }
   157
   158          // Enforce MemoryQoS for cgroups of kube-reserved/system-reserved. For more information,
   159          // see https://github.com/kubernetes/enhancements/tree/master/keps/sig-node/2570-memory-qos
   160          if utilfeature.DefaultFeatureGate.Enabled(kubefeatures.MemoryQoS) {
   161                  if rp.Memory != nil {
   162                          if rp.Unified == nil {
   163                                  rp.Unified = make(map[string]string)
   164                          }
   165                          rp.Unified[Cgroup2MemoryMin] = strconv.FormatInt(*rp.Memory, 10)
   166                  }
   167          }
   168
   169          cgroupConfig := &CgroupConfig{
   170                  Name:               cName,
   171                  ResourceParameters: rp,
   172          }
   173          logger.V(4).Info("Enforcing limits on cgroup", "cgroupName", cName, "cpuShares", cgroupConfig.ResourceParameters.CPUShares, "memory", cgroupConfig.ResourceParameters.Memory, "pidsLimit", cgroupConfig.ResourceParameters.PidsLimit)
   174          if err := cm.cgroupManager.Validate(cgroupConfig.Name); err != nil {
   175                  return err
   176          }
   177          if err := cm.cgroupManager.Update(logger, cgroupConfig); err != nil {
   178                  return err
   179          }
   180          return nil
   181  }
