   183  // getCgroupConfig returns a ResourceConfig object that can be used to create or update cgroups via CgroupManager interface.
   184  func (cm *containerManagerImpl) getCgroupConfig(rl v1.ResourceList, compressibleResourcesOnly bool) *ResourceConfig {
   185          rc := getCgroupConfigInternal(rl, compressibleResourcesOnly)
   186          if rc == nil {
   187                  return nil
   188          }
   189
   190          // In the case of a None policy, cgroupv2 and systemd cgroup manager, we must make sure systemd is aware of the cpuset cgroup.
   191          // By default, systemd will not create it, as we've not chosen to delegate it, and we haven't included it in the Apply() request.
   192          // However, this causes a bug where kubelet restarts unnecessarily (cpuset cgroup is created in the cgroupfs, but systemd
   193          // doesn't know about it and deletes it, and then kubelet doesn't continue because the cgroup isn't configured as expected).
   194          // An alternative is to delegate the `cpuset` cgroup to the kubelet, but that would require some plumbing in libcontainer,
   195          // and this is sufficient.
   196          // Only do so on None policy, as Static policy will do its own updating of the cpuset.
   197          // Please see the comment on policy none's GetAllocatableCPUs
   198          if cm.cpuManager.GetAllocatableCPUs().IsEmpty() {
   199                  rc.CPUSet = cm.cpuManager.GetAllCPUs()
   200          }
   201
   202          return rc
   203  }
