   137  // cgroupCommon implements common tasks
   138  // that are valid for both cgroup v1 and v2.
   139  // This prevents duplicating the code between
   140  // v1 and v2 specific implementations.
   141  type cgroupCommon struct {
   142          // subsystems holds information about all the
   143          // mounted cgroup subsystems on the node
   144          subsystems *CgroupSubsystems
   145
   146          // useSystemd tells if systemd cgroup manager should be used.
   147          useSystemd bool
   148  }
   149
   150  // Make sure that cgroupV1impl and cgroupV2impl implement the CgroupManager interface
   151  var _ CgroupManager = &cgroupV1impl{}
   152  var _ CgroupManager = &cgroupV2impl{}
   153
   154  // NewCgroupManager is a factory method that returns a CgroupManager
   155  func NewCgroupManager(logger klog.Logger, cs *CgroupSubsystems, cgroupDriver string) CgroupManager {
   156          if libcontainercgroups.IsCgroup2UnifiedMode() {
   157                  return NewCgroupV2Manager(logger, cs, cgroupDriver)
   158          }
   159          return NewCgroupV1Manager(logger, cs, cgroupDriver)
   160  }
   161
   162  func newCgroupCommon(logger klog.Logger, cs *CgroupSubsystems, cgroupDriver string) cgroupCommon {
   163          return cgroupCommon{
   164                  subsystems: cs,
   165                  useSystemd: cgroupDriver == "systemd",
   166          }
   167  }
   168
   169  // Name converts the cgroup to the driver specific value in cgroupfs form.
   170  // This always returns a valid cgroupfs path even when systemd driver is in use!
   171  func (m *cgroupCommon) Name(name CgroupName) string {
   172          if m.useSystemd {
   173                  return name.ToSystemd()
   174          }
   175          return name.ToCgroupfs()
   176  }
   177
   178  // CgroupName converts the literal cgroupfs name on the host to an internal identifier.
   179  func (m *cgroupCommon) CgroupName(name string) CgroupName {
   180          if m.useSystemd {
   181                  return ParseSystemdToCgroupName(name)
   182          }
   183          return ParseCgroupfsToCgroupName(name)
   184  }
   185
   186  // buildCgroupPaths builds a path to each cgroup subsystem for the specified name.
   187  func (m *cgroupCommon) buildCgroupPaths(name CgroupName) map[string]string {
   188          cgroupFsAdaptedName := m.Name(name)
   189          cgroupPaths := make(map[string]string, len(m.subsystems.MountPoints))
   190          for key, val := range m.subsystems.MountPoints {
   191                  cgroupPaths[key] = path.Join(val, cgroupFsAdaptedName)
   192          }
