   360  func (m *manager) removeStaleState(rootLogger logr.Logger) {
   361          // Only once all sources are ready do we attempt to remove any stale state.
   362          // This ensures that the call to `m.activePods()` below will succeed with
   363          // the actual active pods list.
   364          if !m.sourcesReady.AllReady() {
   365                  return
   366          }
   367
   368          // We grab the lock to ensure that no new containers will grab CPUs while
   369          // executing the code below. Without this lock, its possible that we end up
   370          // removing state that is newly added by an asynchronous call to
   371          // AddContainer() during the execution of this code.
   372          m.Lock()
   373          defer m.Unlock()
   374
   375          // Get the list of active pods.
   376          activePods := m.activePods()
   377
   378          // Build a list of (podUID, containerName) pairs for all containers in all active Pods.
   379          activeContainers := make(map[string]map[string]struct{})
   380          for _, pod := range activePods {
   381                  activeContainers[string(pod.UID)] = make(map[string]struct{})
   382                  for _, container := range append(pod.Spec.InitContainers, pod.Spec.Containers...) {
   383                          activeContainers[string(pod.UID)][container.Name] = struct{}{}
   384                  }
   385          }
   386
   387          // Loop through the CPUManager state. Remove any state for containers not
   388          // in the `activeContainers` list built above.
   389          assignments := m.state.GetCPUAssignments()
   390          for podUID := range assignments {
   391                  for containerName := range assignments[podUID] {
   392                          logger := klog.LoggerWithValues(rootLogger, "podUID", podUID, "containerName", containerName)
   393
   394                          if _, ok := activeContainers[podUID][containerName]; ok {
   395                                  logger.V(5).Info("container still active")
   396                                  continue
   397                          }
   398
   399                          logger.V(2).Info("removing container")
   400                          err := m.policyRemoveContainerByRef(logger, podUID, containerName)
   401                          if err != nil {
   402                                  logger.Error(err, "failed to remove container")
   403                          }
   404                  }
   405          }
   406
   407          m.containerMap.Visit(func(podUID, containerName, containerID string) {
   408                  logger := klog.LoggerWithValues(rootLogger, "podUID", podUID, "containerName", containerName)
   409                  if _, ok := activeContainers[podUID][containerName]; ok {
   410                          logger.V(5).Info("containerMap: container still active")
   411                          return
   412                  }
   413                  logger.V(2).Info("containerMap: removing container")
   414                  err := m.policyRemoveContainerByRef(logger, podUID, containerName)
   415                  if err != nil {
   416                          logger.Error(err, "containerMap: failed to remove container")
   417                  }
   418          })
   419  }
