   421  func (m *manager) reconcileState(ctx context.Context) (success []reconciledContainer, failure []reconciledContainer) {
   422          success = []reconciledContainer{}
   423          failure = []reconciledContainer{}
   424
   425          rootLogger := klog.FromContext(ctx)
   426
   427          m.removeStaleState(rootLogger)
   428          for _, pod := range m.activePods() {
   429                  podLogger := klog.LoggerWithValues(rootLogger, "pod", klog.KObj(pod))
   430
   431                  pstatus, ok := m.podStatusProvider.GetPodStatus(pod.UID)
   432                  if !ok {
   433                          podLogger.V(5).Info("skipping pod; status not found")
   434                          failure = append(failure, reconciledContainer{pod.Name, "", ""})
   435                          continue
   436                  }
   437
   438                  allContainers := pod.Spec.InitContainers
   439                  allContainers = append(allContainers, pod.Spec.Containers...)
   440                  for _, container := range allContainers {
   441                          logger := klog.LoggerWithValues(podLogger, "containerName", container.Name)
   442
   443                          containerID, err := findContainerIDByName(&pstatus, container.Name)
   444                          if err != nil {
   445                                  logger.V(5).Info("skipping container; ID not found in pod status", "err", err)
   446                                  failure = append(failure, reconciledContainer{pod.Name, container.Name, ""})
   447                                  continue
   448                          }
   449
   450                          cstatus, err := findContainerStatusByName(&pstatus, container.Name)
   451                          if err != nil {
   452                                  logger.V(5).Info("skipping container; container status not found in pod status", "err", err)
   453                                  failure = append(failure, reconciledContainer{pod.Name, container.Name, ""})
   454                                  continue
   455                          }
   456
   457                          if cstatus.State.Waiting != nil ||
   458                                  (cstatus.State.Waiting == nil && cstatus.State.Running == nil && cstatus.State.Terminated == nil) {
   459                                  logger.V(4).Info("skipping container; container still in the waiting state", "err", err)
   460                                  failure = append(failure, reconciledContainer{pod.Name, container.Name, ""})
   461                                  continue
   462                          }
   463
   464                          m.Lock()
   465                          if cstatus.State.Terminated != nil {
   466                                  // The container is terminated but we can't call m.RemoveContainer()
   467                                  // here because it could remove the allocated cpuset for the container
   468                                  // which may be in the process of being restarted.  That would result
   469                                  // in the container losing any exclusively-allocated CPUs that it
   470                                  // was allocated.
   471                                  _, _, err := m.containerMap.GetContainerRef(containerID)
   472                                  if err == nil {
   473                                          logger.V(4).Info("ignoring terminated container", "containerID", containerID)
   474                                  }
   475                                  m.Unlock()
   476                                  continue
   477                          }
   478
   479                          // Once we make it here we know we have a running container.
   480                          // Idempotently add it to the containerMap incase it is missing.
   481                          // This can happen after a kubelet restart, for example.
   482                          m.containerMap.Add(string(pod.UID), container.Name, containerID)
   483                          m.Unlock()
   484
   485                          cset := m.state.GetCPUSetOrDefault(string(pod.UID), container.Name)
   486                          if cset.IsEmpty() {
   487                                  // NOTE: This should not happen outside of tests.
   488                                  logger.V(2).Info("ReconcileState: skipping container; empty cpuset assigned")
   489                                  failure = append(failure, reconciledContainer{pod.Name, container.Name, containerID})
   490                                  continue
   491                          }
   492
   493                          lcset := m.lastUpdateState.GetCPUSetOrDefault(string(pod.UID), container.Name)
   494                          if !cset.Equals(lcset) {
   495                                  logger.V(5).Info("updating container", "containerID", containerID, "cpuSet", cset)
   496                                  err = m.updateContainerCPUSet(ctx, containerID, cset)
   497                                  if err != nil {
   498                                          logger.Error(err, "failed to update container", "containerID", containerID, "cpuSet", cset)
   499                                          failure = append(failure, reconciledContainer{pod.Name, container.Name, containerID})
   500                                          continue

200          burstableCPUShares := MilliCPUToShares(burstablePodCPURequest)
   201          configs[v1.PodQOSBurstable].ResourceParameters.CPUShares = &burstableCPUShares
   202          return nil
